/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // Use a variation of Dijkstra's algorithm or Multi-Source BFS.
    // Since we are looking for the minimum time (distance) to reach a cell,
    // and the "cost" to reach is time (which is uniform 1 per step),
    // a standard BFS approach adapted for multiple sources works, but we need to handle the color rule.

    // The rule is: if multiple colors reach at the same time, the max color wins.
    // This suggests we need to track (time, color) for each cell.

    // State in priority queue: [time, row, col, color]
    // We prioritize by time (shortest time first).
    // If times are equal, we prioritize by color (larger color first, since larger color wins ties).

    // A min-heap based on time, then max-heap based on color (for tie-breaking)
    // In JavaScript, we'll simulate a priority queue using an array and manual sorting/searching,
    // or use a custom implementation if performance is critical, but given N*M <= 10^5, 
    // a standard BFS structure combined with careful updates might suffice.

    // Let's use a structure that tracks the best known state for each cell: [min_time, max_color_at_min_time]
    // Initialize grid: [time, color]. Time = infinity, Color = 0.
    const INF = n * m + 1; // A time larger than any possible shortest path
    const grid = Array(n).fill(0).map(() => Array(m).fill(null).map(() => ({ time: INF, color: 0 })));

    // Priority Queue: Stores [time, -color, r, c]
    // We use -color because JS sort is ascending, and we want max color to have higher priority when times are equal.
    const pq = [];

    for (const [r, c, color] of sources) {
        const time = 0;
        // Set initial state
        grid[r][c] = { time: 0, color: color };
        // Push to PQ: [time, -color, r, c]
        pq.push([time, -color, r, c]);
    }

    // Custom comparator for PQ: min time, then max color (min -color)
    const compare = (a, b) => {
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Smaller time first
        }
        return a[1] - b[1]; // Smaller -color first (i.e., larger color first)
    };

    // Simple manual heap simulation (using sort/splice for small N*M, though less efficient than a proper heap)
    // For N*M <= 10^5, using array sorting inside the loop might TLE, but let's try to use array methods simulating extraction.
    // A proper Binary Heap implementation would be ideal, but for contest constraints, we simulate the logic flow.

    // Since N*M is small enough (10^5), a standard BFS structure where we process nodes in increasing order of time
    // is the goal. Dijkstra's relaxation approach ensures this.

    // Instead of a full heap, let's use a standard array and sort it *only* when extracting the next minimum, 
    // or use a queue-based BFS structure if we can ensure the color tie-breaker doesn't invalidate the BFS property too much.

    // Because the "cost" (time) is always 1, a standard BFS works IF the tie-breaker (color) is handled correctly upon insertion/update.
    // The rule is: if two paths arrive at time T, the one with max color wins.

    // Let's stick to Dijkstra's structure (PQ) as it naturally handles the earliest arrival time.

    // Helper to extract min element (Dijkstra's step)
    const extractMin = (queue) => {
        if (queue.length === 0) return null;
        queue.sort(compare); // Sort to find the minimum element
        return queue.shift();
    };

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    while (pq.length > 0) {
        // Extract the element with minimum time, and then maximum color
        const [time, negColor, r, c] = extractMin(pq);
        const color = -negColor;

        // Check for stale entries (we might have pushed worse states earlier)
        // If the current state extracted is worse than the already recorded best state, skip.
        // "Worse" means later time OR same time but smaller color.
        if (time > grid[r][c].time || (time === grid[r][c].time && color < grid[r][c].color)) {
            continue;
        }

        // Explore neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const newTime = time + 1;
                const neighborState = grid[nr][nc];

                // Check if this new path is better than the currently recorded path for (nr, nc)
                let shouldUpdate = false;

                if (newTime < neighborState.time) {
                    // Case 1: Reached strictly earlier. Always update.
                    shouldUpdate = true;
                } else if (newTime === neighborState.time) {
                    // Case 2: Reached at the same time. Update only if the new color is larger.
                    if (color > neighborState.color) {
                        shouldUpdate = true;
                    }
                }
                // If newTime > neighborState.time, we ignore it (slower path).

                if (shouldUpdate) {
                    // Update the grid state
                    grid[nr][nc] = { time: newTime, color: color };

                    // Push the new state to the PQ
                    pq.push([newTime, -color, nr, nc]);
                }
            }
        }
    }

    // Final result construction
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            // Since the process continues until no more cells can be colored, 
            // every reachable cell will have a finite time/color.
            // If it's uncolored (time=INF), the color remains 0, which is correct if 0 was the default uncolored state,
            // but based on problem statement, all cells must eventually get *some* color if reachable from a source.
            // If a cell is unreachable, its color remains 0, which is the initial uncolored state.
            result[r][c] = grid[r][c].color;
        }
    }

    return result;
}

